import{_ as e,c as o,o as s,ah as r}from"./chunks/framework.RCw5T9E9.js";const c=JSON.parse('{"title":"Settings management","description":"","frontmatter":{"title":"Settings management"},"headers":[],"relativePath":"options/settings_management.md","filePath":"options/settings_management.md"}'),a={name:"options/settings_management.md"};function n(i,t,l,g,d,p){return s(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="save-import-and-export" tabindex="-1">Save, import, and export <a class="header-anchor" href="#save-import-and-export" aria-label="Permalink to &quot;Save, import, and export&quot;">​</a></h1><p><strong>Options → General</strong> ends with <strong>Import</strong>, <strong>Export</strong>, and <strong>Reset</strong>. They work in <strong>extension</strong> and <strong>standalone</strong>, but <strong>storage backends</strong> and <strong>export payload shape</strong> differ.</p><p>Everyday edits <strong>autosave</strong> (debounced) — there is no separate Save button for normal fields.</p><p>A short comparison of where bytes go: <a href="/qa-tools/docs/install.html#storage">Installation → Where settings are stored</a>.</p><hr><h2 id="normal-persistence-paths" tabindex="-1">Normal persistence paths <a class="header-anchor" href="#normal-persistence-paths" aria-label="Permalink to &quot;Normal persistence paths&quot;">​</a></h2><h3 id="extension-chrome-edge" tabindex="-1">Extension (Chrome / Edge) <a class="header-anchor" href="#extension-chrome-edge" aria-label="Permalink to &quot;Extension (Chrome / Edge)&quot;">​</a></h3><p>On autosave / import the background worker:</p><ol><li>Writes the <strong>settings object</strong> (options, tables, Network/Props rules, …) to <strong>IndexedDB</strong> for the extension — primary durable store.</li><li><strong>Mirrors</strong> the structure to <strong><code>chrome.storage.local</code></strong> under a key like <strong><code>vue-inspector-settings</code></strong> for compatibility and quick access.</li></ol><p>Binary Customize files are <strong>not</strong> inlined in JSON — the object stores <strong>ids/metadata</strong> while blobs sit in <strong><code>vue-inspector-media</code></strong> IndexedDB. Keeps the settings blob small/fast to load.</p><h3 id="standalone" tabindex="-1">Standalone <a class="header-anchor" href="#standalone" aria-label="Permalink to &quot;Standalone&quot;">​</a></h3><p>Settings go through the local storage adapter into a <strong>central KV</strong> store (e.g. <strong><code>inspector-settings</code></strong> in IndexedDB via the <strong>storage iframe</strong>). <strong>Not</strong> <code>chrome.storage</code> — there is no installed extension.</p><p>Decorative media uses the same storage perimeter with a <strong>total size budget</strong> (see <a href="/qa-tools/docs/options/customize.html">Customize</a>).</p><p><strong>sessionStorage</strong> may cache for first paint after reload — not a substitute for durable storage.</p><hr><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p><strong>Export</strong> downloads text named like <code>vue-inspector-settings-YYYY-MM-DD.txt</code> containing pretty-printed JSON of in-memory settings.</p><ul><li><strong>Standalone:</strong> for <code>savedFiles</code> rows backed by blobs, export may inline <strong>data URIs</strong> so the backup is <strong>portable</strong> across browsers/machines.</li><li><strong>Extension:</strong> data URI payloads for heavy files are usually <strong>stripped</strong> — you get structure/options; re-copy media locally or re-import a <strong>rich</strong> standalone export if you need bytes.</li></ul><p>Use Export for <strong>backups</strong>, <strong>migration</strong> (especially standalone), and <strong>versioning</strong> presets as plain text.</p><hr><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p><strong>Import</strong> picks a file; expected <strong>JSON</strong> matches export (filter often <code>*.txt</code>).</p><ol><li>Parse and <strong>merge with defaults</strong>: unknown keys drop; legacy shapes <strong>migrate</strong> when possible.</li><li>Result loads into the same options model, then <strong>writes once</strong> to durable storage (extension or standalone).</li><li>UI refreshes dependent lists (breakpoints, mocks, …).</li></ol><p>Blobs are <strong>not duplicated</strong> on write — JSON mostly carries ids; importing a <strong>standalone</strong> export with embedded data URIs hydrates attachments; importing a <strong>trimmed</strong> extension export moves options/lists — you may <strong>re-pick</strong> backgrounds in Customize afterward.</p><p>Bad format <strong>aborts</strong> with an error in the form.</p><p>Import <strong>overwrites</strong> current keys present in the file. <strong>Export</strong> first if you need rollback.</p><hr><h2 id="reset" tabindex="-1">Reset <a class="header-anchor" href="#reset" aria-label="Permalink to &quot;Reset&quot;">​</a></h2><p><strong>Reset</strong> restores factory defaults and clears related <strong>media</strong> stores. Extension path also clears IndexedDB settings keys and <code>chrome.storage.local</code> inspector keys. Standalone writes the reset through the same adapter as normal saves.</p><p><strong>Irreversible</strong> without a prior export.</p><p>Partial Auto Run reset (without full wipe) exists via the extension <strong>popup</strong> — see <a href="/qa-tools/docs/options/auto_run.html">Auto run</a>. <strong>Reset</strong> here clears the <strong>entire</strong> profile.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/install.html#storage">Installation — storage</a></li><li><a href="/qa-tools/docs/options/customize.html">Customize</a></li><li><a href="/qa-tools/docs/options/auto_run.html">Auto run</a></li></ul>',34)])])}const m=e(a,[["render",n]]);export{c as __pageData,m as default};
